164: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::decodeTrailers(
165:     Http::ResponseTrailerMapPtr&& trailers) {
166:   auto maybe_grpc_status = Grpc::Common::getGrpcStatus(*trailers);
167:   auto grpc_status =
168:       maybe_grpc_status
169:           ? maybe_grpc_status.value()
170:           : static_cast<Grpc::Status::GrpcStatus>(Grpc::Status::WellKnownGrpcStatus::Internal);
171:   const std::string grpc_message =
172:       maybe_grpc_status ? Grpc::Common::getGrpcMessage(*trailers) : "invalid gRPC status";
173:   onRpcComplete(grpc_status, grpc_message, true);
174: }
