365: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::logHealthCheckStatus(
366:     Grpc::Status::GrpcStatus grpc_status, const std::string& grpc_message) {
367:   const char* service_status;
368:   if (!health_check_response_) {
369:     service_status = "rpc_error";
370:   } else {
371:     switch (health_check_response_->status()) {
372:     case grpc::health::v1::HealthCheckResponse::SERVING:
373:       service_status = "serving";
374:       break;
375:     case grpc::health::v1::HealthCheckResponse::NOT_SERVING:
376:       service_status = "not_serving";
377:       break;
378:     case grpc::health::v1::HealthCheckResponse::UNKNOWN:
379:       service_status = "unknown";
380:       break;
381:     case grpc::health::v1::HealthCheckResponse::SERVICE_UNKNOWN:
382:       service_status = "service_unknown";
383:       break;
384:     default:
385:       service_status = "unknown_healthcheck_response";
386:       break;
387:     }
388:   }
389:   std::string grpc_status_message;
390:   if (grpc_status != Grpc::Status::WellKnownGrpcStatus::Ok && !grpc_message.empty()) {
391:     grpc_status_message = fmt::format("{} ({})", grpc_status, grpc_message);
392:   } else {
393:     grpc_status_message = absl::StrCat("", grpc_status);
394:   }
395: 
396:   ENVOY_CONN_LOG(debug, "hc grpc_status={} service_status={} health_flags={}", *client_,
397:                  grpc_status_message, service_status, HostUtility::healthFlagsToString(*host_));
398: }
