31: bool Common::hasGrpcContentType(const Http::RequestOrResponseHeaderMap& headers) {
32:   const absl::string_view content_type = headers.getContentTypeValue();
33:   // Content type is gRPC if it is exactly "application/grpc" or starts with
34:   // "application/grpc+". Specifically, something like application/grpc-web is not gRPC.
35:   return absl::StartsWith(content_type, Http::Headers::get().ContentTypeValues.Grpc) &&
36:          (content_type.size() == Http::Headers::get().ContentTypeValues.Grpc.size() ||
37:           content_type[Http::Headers::get().ContentTypeValues.Grpc.size()] == '+');
38: }
39: 
40: bool Common::hasConnectProtocolVersionHeader(const Http::RequestOrResponseHeaderMap& headers) {
41:   return !headers.get(Http::CustomHeaders::get().ConnectProtocolVersion).empty();
42: }
43: 
44: bool Common::hasConnectStreamingContentType(const Http::RequestOrResponseHeaderMap& headers) {
45:   // Consider the request a connect request if the content type starts with "application/connect+".
46:   static constexpr absl::string_view connect_prefix{"application/connect+"};
47:   const absl::string_view content_type = headers.getContentTypeValue();
48:   return absl::StartsWith(content_type, connect_prefix);
49: }
50: 
51: bool Common::hasProtobufContentType(const Http::RequestOrResponseHeaderMap& headers) {
52:   return headers.getContentTypeValue() == Http::Headers::get().ContentTypeValues.Protobuf;
53: }
54: 
55: bool Common::isGrpcRequestHeaders(const Http::RequestHeaderMap& headers) {
56:   if (!headers.Path()) {
57:     return false;
58:   }
59:   return hasGrpcContentType(headers);
60: }
61: 
62: bool Common::isConnectRequestHeaders(const Http::RequestHeaderMap& headers) {
63:   if (!headers.Path()) {
64:     return false;
65:   }
66:   return hasConnectProtocolVersionHeader(headers);
67: }
68: 
69: bool Common::isConnectStreamingRequestHeaders(const Http::RequestHeaderMap& headers) {
70:   if (!headers.Path()) {
71:     return false;
72:   }
73:   return hasConnectStreamingContentType(headers);
74: }
75: 
76: bool Common::isProtobufRequestHeaders(const Http::RequestHeaderMap& headers) {
77:   if (!headers.Path()) {
78:     return false;
79:   }
80:   return hasProtobufContentType(headers);
81: }
82: 
83: bool Common::isGrpcResponseHeaders(const Http::ResponseHeaderMap& headers, bool end_stream) {
84:   if (end_stream) {
85:     // Trailers-only response, only grpc-status is required.
86:     return headers.GrpcStatus() != nullptr;
87:   }
88:   if (Http::Utility::getResponseStatus(headers) != enumToInt(Http::Code::OK)) {
89:     return false;
90:   }
91:   return hasGrpcContentType(headers);
92: }
93: 
94: bool Common::isConnectStreamingResponseHeaders(const Http::ResponseHeaderMap& headers) {
95:   if (Http::Utility::getResponseStatus(headers) != enumToInt(Http::Code::OK)) {
96:     return false;
97:   }
98:   return hasConnectStreamingContentType(headers);
99: }
