168: Buffer::InstancePtr Common::serializeToGrpcFrame(const Protobuf::Message& message) {
169:   // http://www.grpc.io/docs/guides/wire.html
170:   // Reserve enough space for the entire message and the 5 byte header.
171:   // NB: we do not use prependGrpcFrameHeader because that would add another BufferFragment and this
172:   // (using a single BufferFragment) is more efficient.
173:   Buffer::InstancePtr body(new Buffer::OwnedImpl());
174:   const uint32_t size = message.ByteSize();
175:   const uint32_t alloc_size = size + 5;
176:   auto reservation = body->reserveSingleSlice(alloc_size);
177:   ASSERT(reservation.slice().len_ >= alloc_size);
178:   uint8_t* current = reinterpret_cast<uint8_t*>(reservation.slice().mem_);
179:   *current++ = 0; // flags
180:   const uint32_t nsize = htonl(size);
181:   safeMemcpyUnsafeDst(current, &nsize);
182:   current += sizeof(uint32_t);
183:   Protobuf::io::ArrayOutputStream stream(current, size, -1);
184:   Protobuf::io::CodedOutputStream codec_stream(&stream);
185:   message.SerializeWithCachedSizes(&codec_stream);
186:   reservation.commit(alloc_size);
187:   return body;
188: }
