29: // [#protodoc-title: Health check]
30: // * Health checking :ref:`architecture overview <arch_overview_health_checking>`.
31: // * If health checking is configured for a cluster, additional statistics are emitted. They are
32: //   documented :ref:`here <config_cluster_manager_cluster_stats>`.
33: 
34: // Endpoint health status.
35: enum HealthStatus {
36:   // The health status is not known. This is interpreted by Envoy as ``HEALTHY``.
37:   UNKNOWN = 0;
38: 
39:   // Healthy.
40:   HEALTHY = 1;
41: 
42:   // Unhealthy.
43:   UNHEALTHY = 2;
44: 
45:   // Connection draining in progress. E.g.,
46:   // `<https://aws.amazon.com/blogs/aws/elb-connection-draining-remove-instances-from-service-with-care/>`_
47:   // or
48:   // `<https://cloud.google.com/compute/docs/load-balancing/enabling-connection-draining>`_.
49:   // This is interpreted by Envoy as ``UNHEALTHY``.
50:   DRAINING = 3;
51: 
52:   // Health check timed out. This is part of HDS and is interpreted by Envoy as
53:   // ``UNHEALTHY``.
54:   TIMEOUT = 4;
55: 
56:   // Degraded.
57:   DEGRADED = 5;
58: }
59: 
60: message HealthStatusSet {
61:   // An order-independent set of health status.
62:   repeated HealthStatus statuses = 1
63:       [(validate.rules).repeated = {items {enum {defined_only: true}}}];
64: }
65: 
66: // [#next-free-field: 27]
67: message HealthCheck {
68:   option (udpa.annotations.versioning).previous_message_type = "envoy.api.v2.core.HealthCheck";
69: 
70:   // Describes the encoding of the payload bytes in the payload.
71:   message Payload {
72:     option (udpa.annotations.versioning).previous_message_type =
73:         "envoy.api.v2.core.HealthCheck.Payload";
74: 
75:     oneof payload {
76:       option (validate.required) = true;
77: 
78:       // Hex encoded payload. E.g., "000000FF".
79:       string text = 1 [(validate.rules).string = {min_len: 1}];
80: 
81:       // Binary payload.
82:       bytes binary = 2;
83:     }
84:   }
85: 
86:   // [#next-free-field: 15]
87:   message HttpHealthCheck {
88:     option (udpa.annotations.versioning).previous_message_type =
89:         "envoy.api.v2.core.HealthCheck.HttpHealthCheck";
90: 
91:     reserved 5, 7;
92: 
93:     reserved "service_name", "use_http2";
94: 
95:     // The value of the host header in the HTTP health check request. If
96:     // left empty (default value), the name of the cluster this health check is associated
97:     // with will be used. The host header can be customized for a specific endpoint by setting the
98:     // :ref:`hostname <envoy_v3_api_field_config.endpoint.v3.Endpoint.HealthCheckConfig.hostname>` field.
99:     string host = 1 [(validate.rules).string = {well_known_regex: HTTP_HEADER_VALUE}];
100: 
101:     // Specifies the HTTP path that will be requested during health checking. For example
102:     // ``/healthcheck``.
103:     string path = 2 [(validate.rules).string = {min_len: 1 well_known_regex: HTTP_HEADER_VALUE}];
104: 
105:     // [#not-implemented-hide:] HTTP specific payload.
106:     Payload send = 3;
107: 
108:     // Specifies a list of HTTP expected responses to match in the first ``response_buffer_size`` bytes of the response body.
109:     // If it is set, both the expected response check and status code determine the health check.
110:     // When checking the response, “fuzzy” matching is performed such that each payload block must be found,
111:     // and in the order specified, but not necessarily contiguous.
112:     //
113:     // .. note::
114:     //
115:     //   It is recommended to set ``response_buffer_size`` based on the total Payload size for efficiency.
116:     //   The default buffer size is 1024 bytes when it is not set.
117:     repeated Payload receive = 4;
118: 
119:     // Specifies the size of response buffer in bytes that is used to Payload match.
120:     // The default value is 1024. Setting to 0 implies that the Payload will be matched against the entire response.
121:     google.protobuf.UInt64Value response_buffer_size = 14 [(validate.rules).uint64 = {gte: 0}];
122: 
123:     // Specifies a list of HTTP headers that should be added to each request that is sent to the
124:     // health checked cluster. For more information, including details on header value syntax, see
125:     // the documentation on :ref:`custom request headers
126:     // <config_http_conn_man_headers_custom_request_headers>`.
127:     repeated HeaderValueOption request_headers_to_add = 6
128:         [(validate.rules).repeated = {max_items: 1000}];
129: 
130:     // Specifies a list of HTTP headers that should be removed from each request that is sent to the
131:     // health checked cluster.
132:     repeated string request_headers_to_remove = 8 [(validate.rules).repeated = {
133:       items {string {well_known_regex: HTTP_HEADER_NAME strict: false}}
134:     }];
135: 
136:     // Specifies a list of HTTP response statuses considered healthy. If provided, replaces default
137:     // 200-only policy - 200 must be included explicitly as needed. Ranges follow half-open
138:     // semantics of :ref:`Int64Range <envoy_v3_api_msg_type.v3.Int64Range>`. The start and end of each
139:     // range are required. Only statuses in the range [100, 600) are allowed.
140:     repeated type.v3.Int64Range expected_statuses = 9;
141: 
142:     // Specifies a list of HTTP response statuses considered retriable. If provided, responses in this range
143:     // will count towards the configured :ref:`unhealthy_threshold <envoy_v3_api_field_config.core.v3.HealthCheck.unhealthy_threshold>`,
144:     // but will not result in the host being considered immediately unhealthy. Ranges follow half-open semantics of
145:     // :ref:`Int64Range <envoy_v3_api_msg_type.v3.Int64Range>`. The start and end of each range are required.
146:     // Only statuses in the range [100, 600) are allowed. The :ref:`expected_statuses <envoy_v3_api_field_config.core.v3.HealthCheck.HttpHealthCheck.expected_statuses>`
147:     // field takes precedence for any range overlaps with this field i.e. if status code 200 is both retriable and expected, a 200 response will
148:     // be considered a successful health check. By default all responses not in
149:     // :ref:`expected_statuses <envoy_v3_api_field_config.core.v3.HealthCheck.HttpHealthCheck.expected_statuses>` will result in
150:     // the host being considered immediately unhealthy i.e. if status code 200 is expected and there are no configured retriable statuses, any
151:     // non-200 response will result in the host being marked unhealthy.
152:     repeated type.v3.Int64Range retriable_statuses = 12;
153: 
154:     // Use specified application protocol for health checks.
155:     type.v3.CodecClientType codec_client_type = 10 [(validate.rules).enum = {defined_only: true}];
156: 
157:     // An optional service name parameter which is used to validate the identity of
158:     // the health checked cluster using a :ref:`StringMatcher
159:     // <envoy_v3_api_msg_type.matcher.v3.StringMatcher>`. See the :ref:`architecture overview
160:     // <arch_overview_health_checking_identity>` for more information.
161:     type.matcher.v3.StringMatcher service_name_matcher = 11;
162: 
